// We want to control preemption here. Stacked borrows interferes by having its own accesses.
//@compile-flags: -Zmiri-deterministic-concurrency -Zmiri-disable-stacked-borrows

use std::thread;

#[derive(Copy, Clone)]
struct MakeSend(*const i32);
unsafe impl Send for MakeSend {}

fn main() {
    race(0); //~ERROR: Data race detected between (1) non-atomic read on thread `unnamed-1` and (2) deallocation on thread `main`
}

// Using an argument for the ptr to point to, since those do not get StorageDead.
fn race(local: i32) {
    let ptr = MakeSend(&local as *const i32);
    thread::spawn(move || {
        let ptr = ptr; // avoid field capturing
        let _val = unsafe { *ptr.0 };
    });
    // Make the other thread go first so that it does not UAF.
    thread::yield_now();
    // Deallocating the local (when `main` returns)
    // races with the read in the other thread.
}

examples.fixed_code:
use std::thread;

fn main() {
    race(0);
}

// Using an argument for the ptr to point to, since those do not get StorageDead.
fn race(local: i32) {
    // thread::scope ensures all threads spawned within are joined 
    // before the function returns, preventing the Use-After-Free.
    thread::scope(|s| {
        s.spawn(|| {
            // We can now safely reference `local` from the parent stack.
            // Scoped threads allow borrowing from the local stack frame.
            let _val = local;
        });
        // Make the other thread go first. 
        // Because of the scope, the main thread will wait for the spawned 
        // thread to finish before `race` returns and `local` is dropped.
        thread::yield_now();
    });
}

