// targets since we check the `PassMode`; here we ensure that we catch it on *all* targets
// (in particular, on x86-64 the pass mode is `Indirect` for both of these).
struct S(
    #[allow(dead_code)] i32,
    #[allow(dead_code)] i32,
    #[allow(dead_code)] i32,
    #[allow(dead_code)] i32,
);
